{
 "module_name": "Expression Matrix Preprocessing",
 "goal": "对未知组学表达矩阵执行标准化预处理流程：缺失值填充、列和归一化、对数变换（若最大值>100）、中位数缩放，并将结果保存至tmp目录。",
 "input_files": [
 "G:/OmicsWorks/test/metabolism/expression.csv",
 "G:/OmicsWorks/test/metabolism/sampleinfo.csv"
 ],
 "output_files": [
 "G:/OmicsWorks/test/metabolism/demo/tmp/preprocessed_expression.csv"
 ],
 "execution_steps": [
 {
 "action": "读取表达矩阵（expression.csv）和样本信息表（sampleinfo.csv），将行名设为分子ID，列名设为样本ID；检查数据维度、缺失值分布及最大值范围。",
 "goal": "加载原始数据并评估数据特征，为后续预处理提供依据。"
 },
 {
 "action": "对每个分子（行）用该行最小正值的一半填充缺失值；然后对每列进行总和归一化（将每个表达值除以该列总和，得到相对丰度）；接着判断最大值是否大于100：若是则对所有值加1后取自然对数（ln(x+1)）；最后对每行进行中位数缩放（每行的值减去该行中位数）。",
 "goal": "执行标准预处理流程，消除技术偏差和量纲差异，使数据适合下游统计分析。"
 },
 {
 "action": "将预处理后的矩阵保存为CSV文件，保留分子ID为第一列，样本ID为列名。输出文件路径：G:/OmicsWorks/test/metabolism/demo/tmp/preprocessed_expression.csv。",
 "goal": "持久化处理结果，供后续模块调用。"
 }
 ],
 "notes": "本数据集包含QC组样本（如Fc16YH_QC1等），预处理时不作特殊处理，所有样本统一处理；由于研究主题未指定预处理异常，因此遵循标准流程；对数变换使用ln(x+1)以避免log(0)问题；中位数缩放后表达值可能出现负值，属于正常现象。"
}
